tag.description:
{
    Optional. Data for populating the Message object.

    @type string $name
          Required. The resource name for the ProductSet to modify.
          Format is:
          `projects/PROJECT_ID/locations/LOC_ID/productSets/PRODUCT_SET_ID`
    @type string $product
          Required. The resource name for the Product to be added to this ProductSet.
          Format is:
          `projects/PROJECT_ID/locations/LOC_ID/products/PRODUCT_ID`
}

{
    Optional. Data for populating the Message object.

    @type \Google\Cloud\Vision\V1\InputConfig $input_config
          Required. Information about the input file.
    @type \Google\Cloud\Vision\V1\Feature[] $features
          Required. Requested features.
    @type \Google\Cloud\Vision\V1\ImageContext $image_context
          Additional context that may accompany the image(s) in the file.
    @type int[] $pages
          Pages of the file to perform image annotation.
          Pages starts from 1, we assume the first page of the file is page 1.
          At most 5 pages are supported per request. Pages can be negative.
          Page 1 means the first page.
          Page 2 means the second page.
          Page -1 means the last page.
          Page -2 means the second to the last page.
          If the file is GIF instead of PDF or TIFF, page refers to GIF frames.
          If this field is empty, by default the service performs image annotation
          for the first 5 pages of the file.
}

{
    Optional. Data for populating the Message object.

    @type \Google\Cloud\Vision\V1\InputConfig $input_config
          Information about the file for which this response is generated.
    @type \Google\Cloud\Vision\V1\AnnotateImageResponse[] $responses
          Individual responses to images found within the file. This field will be
          empty if the `error` field is set.
    @type int $total_pages
          This field gives the total number of pages in the file.
    @type \Google\Rpc\Status $error
          If set, represents the error message for the failed request. The
          `responses` field will not be set in this case.
}

{
    Optional. Data for populating the Message object.

    @type \Google\Cloud\Vision\V1\Image $image
          The image to be processed.
    @type \Google\Cloud\Vision\V1\Feature[] $features
          Requested features.
    @type \Google\Cloud\Vision\V1\ImageContext $image_context
          Additional context that may accompany the image.
}

{
    Optional. Data for populating the Message object.

    @type \Google\Cloud\Vision\V1\FaceAnnotation[] $face_annotations
          If present, face detection has completed successfully.
    @type \Google\Cloud\Vision\V1\EntityAnnotation[] $landmark_annotations
          If present, landmark detection has completed successfully.
    @type \Google\Cloud\Vision\V1\EntityAnnotation[] $logo_annotations
          If present, logo detection has completed successfully.
    @type \Google\Cloud\Vision\V1\EntityAnnotation[] $label_annotations
          If present, label detection has completed successfully.
    @type \Google\Cloud\Vision\V1\LocalizedObjectAnnotation[] $localized_object_annotations
          If present, localized object detection has completed successfully.
          This will be sorted descending by confidence score.
    @type \Google\Cloud\Vision\V1\EntityAnnotation[] $text_annotations
          If present, text (OCR) detection has completed successfully.
    @type \Google\Cloud\Vision\V1\TextAnnotation $full_text_annotation
          If present, text (OCR) detection or document (OCR) text detection has
          completed successfully.
          This annotation provides the structural hierarchy for the OCR detected
          text.
    @type \Google\Cloud\Vision\V1\SafeSearchAnnotation $safe_search_annotation
          If present, safe-search annotation has completed successfully.
    @type \Google\Cloud\Vision\V1\ImageProperties $image_properties_annotation
          If present, image properties were extracted successfully.
    @type \Google\Cloud\Vision\V1\CropHintsAnnotation $crop_hints_annotation
          If present, crop hints have completed successfully.
    @type \Google\Cloud\Vision\V1\WebDetection $web_detection
          If present, web detection has completed successfully.
    @type \Google\Cloud\Vision\V1\ProductSearchResults $product_search_results
          If present, product search has completed successfully.
    @type \Google\Rpc\Status $error
          If set, represents the error message for the operation.
          Note that filled-in image annotations are guaranteed to be
          correct, even when `error` is set.
    @type \Google\Cloud\Vision\V1\ImageAnnotationContext $context
          If present, contextual information is needed to understand where this image
          comes from.
}

{
    Optional. Data for populating the Message object.

    @type \Google\Cloud\Vision\V1\InputConfig $input_config
          Required. Information about the input file.
    @type \Google\Cloud\Vision\V1\Feature[] $features
          Required. Requested features.
    @type \Google\Cloud\Vision\V1\ImageContext $image_context
          Additional context that may accompany the image(s) in the file.
    @type \Google\Cloud\Vision\V1\OutputConfig $output_config
          Required. The desired output location and metadata (e.g. format).
}

